Looking at the code structure and requirements, I need to implement three functions that work with the EAS database using the `sqlgen` library. Here's the complete implementation:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Insert all records in a transaction
  for (const auto& record : records) {
    sqlgen::insert(conn, record).value();
  }
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Create a map to handle different table types and their primary keys
  if constexpr (std::is_same_v<T, Student>) {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"SNo">(std::to_string(record_id))).value();
  } else if constexpr (std::is_same_v<T, Course>) {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"CID">(record_id)).value();
  } else if constexpr (std::is_same_v<T, Score>) {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"ScID">(record_id)).value();
  } else if constexpr (std::is_same_v<T, Major>) {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"MID">(record_id)).value();
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Handle different table types and their primary keys
  if (table_name == "Student") {
    sqlgen::remove<Student>(conn, 
                            sqlgen::where<"SNo">(record_id)).value();
  } else if (table_name == "Course") {
    int id = std::stoi(record_id);
    sqlgen::remove<Course>(conn, 
                          sqlgen::where<"CID">(id)).value();
  } else if (table_name == "Score") {
    int id = std::stoi(record_id);
    sqlgen::remove<Score>(conn, 
                         sqlgen::where<"ScID">(id)).value();
  } else if (table_name == "Major") {
    int id = std::stoi(record_id);
    sqlgen::remove<Major>(conn, 
                         sqlgen::where<"MID">(id)).value();
  }
}
