```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>
#include <stdexcept>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Insert all records
  for (const auto& record : records) {
    sqlgen::insert(conn, record).value();
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const auto& new_value) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Handle different table types based on table_name
  if (table_name == "Student") {
    // For Student table, primary key is SNo (string type)
    // We need to convert record_id to string since SNo is Varchar<10>
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"SNo">(std::to_string(record_id))).value();
  } else if (table_name == "Course") {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"CID">(record_id)).value();
  } else if (table_name == "Score") {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"ScID">(record_id)).value();
  } else if (table_name == "Major") {
    sqlgen::update(conn, 
                   sqlgen::set(col_name.c_str(), new_value),
                   sqlgen::where<"MID">(record_id)).value();
  } else {
    throw std::invalid_argument("Unknown table name: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {

  // Connect to the database
  auto conn = sqlgen::sqlite::connect(db_path).value();

  // Handle different table types and their primary keys
  if (table_name == "Student") {
    sqlgen::remove<Student>(conn, 
                            sqlgen::where<"SNo">(record_id)).value();
  } else if (table_name == "Course") {
    int id = std::stoi(record_id);
    sqlgen::remove<Course>(conn, 
                          sqlgen::where<"CID">(id)).value();
  } else if (table_name == "Score") {
    int id = std::stoi(record_id);
    sqlgen::remove<Score>(conn, 
                         sqlgen::where<"ScID">(id)).value();
  } else if (table_name == "Major") {
    int id = std::stoi(record_id);
    sqlgen::remove<Major>(conn, 
                         sqlgen::where<"MID">(id)).value();
  } else {
    throw std::invalid_argument("Unknown table name: " + table_name);
  }
}
```

Key points about this implementation:

1. **`add_eas_records`**: Uses `sqlgen::insert` to add records to the specified table. The template parameter `T` should match the table structure.

2. **`modify_eas_records_by_id`**: Uses `sqlgen::update` with `sqlgen::set` and `sqlgen::where` to update specific records. Handles different primary key types for each table.

3. **`delete_eas_records_by_id`**: Uses `sqlgen::remove` with `sqlgen::where` to delete records. Converts the `record_id` string to the appropriate type for each table.

4. **Error handling**: Uses `.value()` to extract results from expected types, which will throw exceptions on errors. Also includes basic validation for unknown table names.

5. **Type conversion**: Handles the conversion between string IDs (for Student table) and integer IDs (for other tables) as appropriate.

The implementation follows the `sqlgen` library's patterns and properly handles the different table structures defined in `eas_common.hpp`.

