    ASSERT_TRUE(has_column("Course", "CName"));
    ASSERT_TRUE(has_column("Course", "Term"));
    ASSERT_TRUE(has_column("Course", "CTime"));
    ASSERT_TRUE(has_column("Course", "CScore"));

