 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  // Create database connection
  sqlgen::connection<sqlgen::sqlite> conn("test_db.sqlite");

  // Build the query using sqlgen's query builder
  auto query = sqlgen::select(
      sqlgen::expr("strftime('%Y-%m-%d', {}) as visit_date", PageVisit::visit_time),
      sqlgen::count().as("total_visits"),
      sqlgen::count_distinct(PageVisit::url).as("unique_pages")
    ).from<PageVisit>()
    .group_by(sqlgen::expr("strftime('%Y-%m-%d', {})", PageVisit::visit_time))
    .order_by(sqlgen::expr("strftime('%Y-%m-%d', {})", PageVisit::visit_time));

  // Execute the query and return results
  return conn.query<DailyTraffic>(query);
