Here's the complete implementation of the function using the `sqlgen` library:

```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Create SQLite connection
    sqlgen::SQLiteConnection conn("test_db.sqlite");

    // Start building the query
    auto query = sqlgen::select<Book>();

    // Build conditions dynamically based on provided filters
    sqlgen::Condition condition;

    if (filters.title_keyword.has_value()) {
        condition = condition && sqlgen::condition(&Book::title).like("%" + *filters.title_keyword + "%");
    }

    if (filters.min_year.has_value()) {
        condition = condition && sqlgen::condition(&Book::year) >= *filters.min_year;
    }

    if (filters.genre.has_value()) {
        condition = condition && sqlgen::condition(&Book::genre) == *filters.genre;
    }

    if (filters.max_price.has_value()) {
        condition = condition && sqlgen::condition(&Book::price) <= *filters.max_price;
    }

    // Apply the condition if any filters were provided
    if (!condition.empty()) {
        query = query.where(condition);
    }

    // Execute the query and return results
    return conn.execute(query).fetch_all();
}

}  // namespace query_search_books_by_criteria
```

This implementation:

1. **Connects to the database** using `sqlgen::SQLiteConnection`
2. **Starts with a base SELECT query** using `sqlgen::select<Book>()`
3. **Dynamically builds WHERE clauses** using `sqlgen::Condition` and the `&&` operator to combine conditions
4. **Uses appropriate operators**:
   - `LIKE` with wildcards for title search
   - `>=` for minimum year
   - `==` for exact genre match
   - `<=` for maximum price
5. **Only adds conditions** when the optional parameters have values (using `has_value()`)
6. **Executes the query** and returns all results using `fetch_all()`

The `sqlgen` library handles the SQL generation and parameter binding automatically based on the conditions you build, making the code type-safe and preventing SQL injection vulnerabilities.

