      {1, "New Year Party", Timestamp("2023-01-01 20:00:00"), 
       Timestamp("2023-01-02 02:00:00"), Timestamp("2022-12-01 10:00:00")},
      {2, "Conference", Timestamp("2023-03-15 09:00:00"), 
