```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>
#include <optional>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  // Create SQLite database connection
  sqlgen::SQLiteDatabase db("test_db.sqlite");

  // Create Event table if it doesn't exist
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Event (
      event_id INTEGER PRIMARY KEY,
      event_name TEXT NOT NULL,
      start_time DATETIME NOT NULL,
      end_time DATETIME,
      created_at DATETIME NOT NULL
    )
  )");

  // Clear existing data and insert new events
  db.execute("DELETE FROM Event");

  for (const auto& event : events) {
    auto stmt = db.prepare(R"(
      INSERT INTO Event (event_id, event_name, start_time, end_time, created_at)
      VALUES (?, ?, ?, ?, ?)
    )");

    stmt.bind(1, event.event_id.value());
    stmt.bind(2, event.event_name);
    stmt.bind(3, event.start_time.value());

    if (event.end_time.has_value()) {
      stmt.bind(4, event.end_time.value().value());
    } else {
      stmt.bind(4, nullptr);
    }

    stmt.bind(5, event.created_at.value());
    stmt.execute();
  }

  // Execute temporal analysis query
  auto result = db.executeQuery(R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      CASE 
        WHEN end_time IS NOT NULL THEN 
          JULIANDAY(end_time) - JULIANDAY(start_time)
        ELSE NULL
      END as duration_days
    FROM Event
    WHERE end_time IS NOT NULL
  )");

  std::vector<TemporalAnalysis> analysis_results;

  while (result.next()) {
    TemporalAnalysis analysis;
    analysis.event_id = result.get<int>(0);
    analysis.event_name = result.get<std::string>(1);
    analysis.start_day = result.get<int>(2);
    analysis.start_month = result.get<int>(3);
    analysis.start_year = result.get<int>(4);
    analysis.start_hour = result.get<int>(5);
    analysis.start_minute = result.get<int>(6);
    analysis.start_second = result.get<int>(7);
    analysis.start_weekday = result.get<int>(8);
    analysis.start_epoch = result.get<int64_t>(9);

    auto duration_days = result.get<std::optional<double>>(10);
    if (duration_days.has_value()) {
      analysis.duration_days = duration_days.value();
    }

    analysis_results.push_back(std::move(analysis));
  }

  return analysis_results;
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to SQLite database**: Uses `sqlgen::SQLiteDatabase` to connect to "test_db.sqlite"
2. **Creates Event table**: Ensures the table exists with the correct structure
3. **Inserts events**: Clears existing data and inserts the provided events
4. **Performs temporal analysis**: Executes a comprehensive SQL query that:
   - Extracts date components using SQLite's `strftime` function
   - Calculates weekday information (0=Sunday, 6=Saturday)
   - Converts timestamps to Unix epoch using `strftime('%s')`
   - Calculates duration in days using `JULIANDAY` difference
5. **Returns results**: Maps the SQL results to `TemporalAnalysis` structs and returns them

The implementation handles optional `end_time` values correctly and only includes events that have an end time in the final analysis, as specified in the WHERE clause.

