#include <iostream>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

SQLGEN_ORM(Inventory, Inventory, item_id, name, quantity)

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  try {
    // Create database connection
    sqlgen::sqlite::connection conn("test_db.sqlite");

    // Create table if it doesn't exist
    conn.create_table<Inventory>();

    // Perform upsert (insert or replace) for all items
    conn.replace(items);

    // Verify upsert behavior by reading back items
    for (const auto& item : items) {
      auto result = conn.get<Inventory>(item.item_id);
      if (!result) {
        std::cerr << "Failed to verify item with ID: " << item.item_id << std::endl;
        return false;
      }

      // Check if the retrieved item matches what we inserted
      if (result->name != item.name || result->quantity != item.quantity) {
        std::cerr << "Verification failed for item with ID: " << item.item_id << std::endl;
        std::cerr << "Expected: " << item.name << ", " << item.quantity << std::endl;
        std::cerr << "Got: " << result->name << ", " << result->quantity << std::endl;
        return false;
      }
    }

    std::cout << "Successfully upserted and verified " << items.size() << " items." << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in upsert_inventory_items: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace upsert_inventory_items
