```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct UserFriendCount {
  int user_id;
  std::string username;
  int friend_count;
};

struct MutualFriends {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

struct FriendRecommendation {
  std::string user1_name;
  std::string user2_name;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    std::vector<FriendConnection> results;

    try {
        // Create in-memory SQLite database
        sqlgen::SQLiteDatabase db(":memory:");

        // Create User table
        auto user_table = sqlgen::Table<User>("User")
            .column("user_id", &User::user_id, sqlgen::PRIMARY_KEY | sqlgen::AUTO_INCREMENT)
            .column("username", &User::username, sqlgen::NOT_NULL | sqlgen::UNIQUE)
            .column("email", &User::email, sqlgen::NOT_NULL | sqlgen::UNIQUE)
            .column("join_date", &User::join_date, sqlgen::NOT_NULL)
            .column("city", &User::city);

        // Create Friendship table
        auto friendship_table = sqlgen::Table<Friendship>("Friendship")
            .column("user_id1", &Friendship::user1_id)
            .column("user_id2", &Friendship::user2_id)
            .column("friendship_date", &Friendship::friendship_date, sqlgen::NOT_NULL);

        // Create tables in database
        db.createTable(user_table);
        db.createTable(friendship_table);

        // Insert users
        for (const auto& user : users) {
            db.insert(user_table, user);
        }

        // Insert friendships
        for (const auto& friendship : friendships) {
            db.insert(friendship_table, friendship);
        }

        // 1. Find mutual friends using SELF-JOIN
        std::cout << "=== Mutual Friends Analysis ===" << std::endl;
        auto mutual_friends_query = db.query<MutualFriends>(
            "SELECT u1.username as user1_name, u2.username as user2_name, COUNT(f1.user_id2) as mutual_friends_count "
            "FROM User u1 "
            "INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1 "
            "INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1 "
            "INNER JOIN User u2 ON f2.user_id2 = u2.user_id "
            "WHERE u1.user_id < u2.user_id "
            "  AND EXISTS ( "
            "    SELECT 1 FROM Friendship f3  "
            "    WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id "
            "  ) "
            "GROUP BY u1.user_id, u2.user_id "
            "HAVING COUNT(f1.user_id2) > 0 "
            "ORDER BY mutual_friends_count DESC"
        );

        for (const auto& mutual : mutual_friends_query) {
            std::cout << mutual.user1_name << " and " << mutual.user2_name 
                      << " have " << mutual.mutual_friends_count << " mutual friends" << std::endl;
            results.push_back({mutual.user1_name, mutual.user2_name});
        }

        // 2. Find users with more than average friends using nested query
        std::cout << "\n=== Users with Above Average Friends ===" << std::endl;
        auto above_avg_friends_query = db.query<UserFriendCount>(
            "SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count "
            "FROM User u "
            "LEFT JOIN Friendship f ON u.user_id = f.user_id1 "
            "GROUP BY u.user_id, u.username "
            "HAVING friend_count > ( "
            "  SELECT AVG(friend_count)  "
            "  FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1) as subq "
            ") "
            "ORDER BY friend_count DESC"
        );

        for (const auto& user_count : above_avg_friends_query) {
            std::cout << user_count.username << " has " << user_count.friend_count 
                      << " friends (above average)" << std::endl;
        }

        // 3. Find friend-of-friend relationships
        std::cout << "\n=== Friend-of-Friend Relationships ===" << std::endl;
        auto friend_of_friend_query = db.query<FriendConnection>(
            "SELECT DISTINCT u1.username as user1_name, u3.username as user2_name "
            "FROM User u1 "
            "JOIN Friendship f1 ON u1.user_id = f1.user_id1 "
            "JOIN User u2 ON f1.user_id2 = u2.user_id "
            "JOIN Friendship f2 ON u2.user_id = f2.user_id1 "
            "JOIN User u3 ON f2.user_id2 = u3.user_id "
            "WHERE u1.user_id != u3.user_id "
            "  AND NOT EXISTS ( "
            "    SELECT 1 FROM Friendship f3 "
            "    WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id "
            "  ) "
            "ORDER BY u1.username, u3.username"
        );

        for (const auto& connection : friend_of_friend_query) {
            std::cout << connection.user1_name << " is connected to " 
                      << connection.user2_name << " through a mutual friend" << std::endl;
        }

        // 4. Count friends per user and identify most connected users
        std::cout << "\n=== Friend Count Analysis ===" << std::endl;
        auto friend_count_query = db.query<UserFriendCount>(
            "SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count "
            "FROM User u "
            "LEFT JOIN Friendship f ON u.user_id = f.user_id1 "
            "GROUP BY u.user_id, u.username "
            "ORDER BY friend_count DESC"
        );

        for (const auto& user_count : friend_count_query) {
            std::cout << user_count.username << " has " << user_count.friend_count 
                      << " friends" << std::endl;
        }

        // 5. Find users in the same city who are not yet friends (recommendation)
        std::cout << "\n=== Friend Recommendations (Same City) ===" << std::endl;
        auto recommendation_query = db.query<FriendRecommendation>(
            "SELECT u1.username as user1_name, u2.username as user2_name, u1.city as city "
            "FROM User u1 "
            "JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id "
            "WHERE u1.city IS NOT NULL "
            "  AND NOT EXISTS ( "
            "    SELECT 1 FROM Friendship f "
            "    WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id) "
            "       OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id) "
            "  ) "
            "ORDER BY u1.city, u1.username"
        );

        for (const auto& rec : recommendation_query) {
            std::cout << "Recommend: " << rec.user1_name << " and " << rec.user2_name 
                      << " (both in " << rec.city << ")" << std::endl;
        }

    } catch (const std::exception& e) {
        std::cerr << "Database error: " << e.what() << std::endl;
    }

    return results;
}

}  // namespace analyze_social_network
```

