 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  // Create an in-memory SQLite database
  sqlgen::SQLiteDatabase db(":memory:");

  // Create the OrderItem table
  db.execute(R"(
    CREATE TABLE OrderItem (
      item_id INTEGER PRIMARY KEY,
      order_id INTEGER NOT NULL,
      product_id INTEGER NOT NULL,
      unit_price REAL NOT NULL,
      quantity INTEGER NOT NULL,
      discount_rate REAL,
      tax_rate REAL
    )
  )");

  // Insert all items into the table
  auto insert_stmt = db.prepare(R"(
    INSERT INTO OrderItem (item_id, order_id, product_id, unit_price, quantity, discount_rate, tax_rate)
    VALUES (?, ?, ?, ?, ?, ?, ?)
  )");

  for (const auto& item : items) {
    insert_stmt.bind(1, item.item_id.value);
    insert_stmt.bind(2, item.order_id);
    insert_stmt.bind(3, item.product_id);
    insert_stmt.bind(4, item.unit_price);
    insert_stmt.bind(5, item.quantity);

    if (item.discount_rate.has_value()) {
      insert_stmt.bind(6, item.discount_rate.value());
    } else {
      insert_stmt.bind(6, nullptr);
    }

    if (item.tax_rate.has_value()) {
      insert_stmt.bind(7, item.tax_rate.value());
    } else {
      insert_stmt.bind(7, nullptr);
    }

    insert_stmt.execute();
    insert_stmt.reset();
  }

  // Execute the comprehensive metrics query
  auto query = db.prepare(R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0) as discount_rate,
      COALESCE(tax_rate, 0) as tax_rate,
      (unit_price * quantity) as gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total,
      (unit_price * quantity / quantity) as unit_cost,
      (quantity % 10) as quantity_group,
      (unit_price * 0.3) as estimated_profit
    FROM OrderItem
  )");

  std::vector<OrderMetrics> results;

  while (query.step()) {
    OrderMetrics metrics;
    metrics.item_id = query.get<int>(0);
    metrics.order_id = query.get<int>(1);
    metrics.product_id = query.get<int>(2);
    metrics.unit_price = query.get<double>(3);
    metrics.quantity = query.get<int>(4);
    metrics.discount_rate = query.get<double>(5);
    metrics.tax_rate = query.get<double>(6);
    metrics.gross_total = query.get<double>(7);
    metrics.discounted_total = query.get<double>(8);
    metrics.final_total = query.get<double>(9);
    metrics.unit_cost = query.get<double>(10);
    metrics.quantity_group = query.get<int>(11);
    metrics.estimated_profit = query.get<double>(12);

    results.push_back(metrics);
  }

  return results;
}

}  // namespace calculate_order_metrics
```

