std::vector<Consolidated> join_orders_customers_payments() {
  // Create database connection
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // Build the join query using sqlgen's fluent interface
  auto query = sqlgen::select(
    sqlgen::column<Order>(&Order::order_id),
    sqlgen::column<Customer>(&Customer::name).as("customer_name"),
    sqlgen::column<Payment>(&Payment::amount)
  ).from<Order>()
