   .join<Payment>(sqlgen::on(&Order::order_id, &Payment::order_id))
   .order_by(sqlgen::column<Payment>(&Payment::amount).desc());

  // Execute the query and map results to Consolidated struct
  std::vector<Consolidated> results;
  conn.execute(query, [&results](const Consolidated& consolidated) {
