namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to the SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create table if it doesn't exist (though the problem assumes it exists)
  db.createTable<Note>();

  // First, select all notes to process
  auto notes = db.select<Note>().all();

  std::vector<UpdatedNote> updated_notes;

  // Process each note: replace "foo" with "bar"
  for (const auto& note : notes) {
    // Perform text replacement
    std::string updated_content = note.content;
    size_t pos = 0;
    const std::string target = "foo";
    const std::string replacement = "bar";

    while ((pos = updated_content.find(target, pos)) != std::string::npos) {
      updated_content.replace(pos, target.length(), replacement);
      pos += replacement.length();
    }

    // Update the note in the database
    Note updated_note{note.note_id, updated_content};
    db.update(updated_note);

    // Add to result vector for verification
    updated_notes.push_back(UpdatedNote{note.note_id, updated_content});
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
