    conn.execute("INSERT INTO Account (balance, status) VALUES (2000.0, 'active')");

    // Update balances and statuses using set operations
    auto update_stmt = conn.prepare<Account>(
      sqlgen::update<Account>()
        .set(&Account::balance, 1500.0)
        .set(&Account::status, "updated")
        .where(sqlgen::eq(&Account::account_id, 1))
    );
    update_stmt.execute();

    // Update multiple records with different values
    auto update_stmt2 = conn.prepare<Account>(
      sqlgen::update<Account>()
        .set(&Account::balance, 750.0)
        .set(&Account::status, "modified")
        .where(sqlgen::eq(&Account::account_id, 2))
    );
    update_stmt2.execute();

    // Verify changes persisted
    auto select_stmt = conn.prepare<Account>(
      sqlgen::select<Account>()
        .where(sqlgen::eq(&Account::account_id, 1))
    );

    auto result = select_stmt.execute();
    if (result.empty()) {
      std::cerr << "No account found with ID 1" << std::endl;
      return false;
    }

    const auto& account = result[0];
    if (std::abs(account.balance - 1500.0) > 0.001 || account.status != "updated") {
      std::cerr << "Verification failed for account 1" << std::endl;
      return false;
    }

    // Verify second account
    auto select_stmt2 = conn.prepare<Account>(
      sqlgen::select<Account>()
        .where(sqlgen::eq(&Account::account_id, 2))
    );

    auto result2 = select_stmt2.execute();
    if (result2.empty()) {
      std::cerr << "No account found with ID 2" << std::endl;
      return false;
    }

    const auto& account2 = result2[0];
    if (std::abs(account2.balance - 750.0) > 0.001 || account2.status != "modified") {
      std::cerr << "Verification failed for account 2" << std::endl;
      return false;
    }

    std::cout << "Update set operations completed successfully!" << std::endl;
    return true;

  } catch (const std::exception& e) {
    std::cerr << "Error in update_set_operations: " << e.what() << std::endl;
    return false;
  }
