```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

// Register the structs with sqlgen
SQLGEN_STRUCT(Supplier, supplier_id, name)
SQLGEN_STRUCT(Product, product_id, supplier_id, name)
SQLGEN_STRUCT(SupProd, supplier_name, product_name)

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Create database connection
  sqlgen::database db("test_db.sqlite");

  // Since SQLite doesn't natively support FULL JOIN, we simulate it using UNION of LEFT and RIGHT JOIN
  // First part: LEFT JOIN (all suppliers with their products, if any)
  // Second part: RIGHT JOIN using LEFT JOIN approach (products without suppliers)
  auto query = R"(
    SELECT s.name AS supplier_name, p.name AS product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id

    UNION

    SELECT s.name AS supplier_name, p.name AS product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  // Execute the query and return results
  return db.select<SupProd>(query);
}

}  // namespace full_join_suppliers_products
```

Key points about this implementation:

1. **Struct Registration**: The `SQLGEN_STRUCT` macros register the structs with `sqlgen` so it knows how to map database results to C++ structs.

2. **FULL JOIN Simulation**: Since SQLite doesn't natively support FULL JOIN, we simulate it using a UNION of:
   - A LEFT JOIN (all suppliers with their products)
   - A RIGHT JOIN (achieved via LEFT JOIN with a WHERE clause to get products without suppliers)

3. **Database Connection**: The function creates a connection to "test_db.sqlite" using `sqlgen::database`.

4. **Query Execution**: The `db.select<SupProd>(query)` method executes the SQL query and automatically maps the results to `SupProd` structs.

5. **Optional Handling**: The `product_name` field is `std::optional` to handle cases where suppliers have no products.

This implementation will return all suppliers and all products, matching them where possible and showing NULL/empty for the product name when a supplier has no products, or showing NULL/empty for the supplier name when a product has no supplier.

