#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <memory>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  JoinAnalysis analysis;

  // Create SQLite database connection
  auto db = std::make_shared<sqlgen::SQLiteDB>("test_db.sqlite");

  // Create Department table
  sqlgen::Table<Department> department_table(db, "Department");
  department_table.create_table();

  // Create Employee table  
  sqlgen::Table<Employee> employee_table(db, "Employee");
  employee_table.create_table();

  // Insert department data
  for (const auto& dept : depts) {
    department_table.insert(dept);
  }

  // Insert employee data
  for (const auto& emp : emps) {
    employee_table.insert(emp);
  }

  // 1. INNER JOIN: Employees with assigned departments
  auto inner_join_query = sqlgen::query<JoinResult>()
    .select(
      sqlgen::column<Department>(&Department::department_name).as(&JoinResult::department_name),
      sqlgen::column<Employee>(&Employee::first_name).as(&JoinResult::first_name),
      sqlgen::column<Employee>(&Employee::last_name).as(&JoinResult::last_name),
      sqlgen::column<Employee>(&Employee::salary).as(&JoinResult::salary)
    )
    .from<Department>()
    .inner_join<Employee>().on(
      sqlgen::column<Department>(&Department::department_id) == 
      sqlgen::column<Employee>(&Employee::department_id)
    );

  analysis.inner_join_results = inner_join_query.exec(db);

  // 2. LEFT JOIN: All employees (even without departments)
  auto left_join_query = sqlgen::query<JoinResult>()
    .select(
      sqlgen::column<Department>(&Department::department_name).as(&JoinResult::department_name),
      sqlgen::column<Employee>(&Employee::first_name).as(&JoinResult::first_name),
      sqlgen::column<Employee>(&Employee::last_name).as(&JoinResult::last_name),
      sqlgen::column<Employee>(&Employee::salary).as(&JoinResult::salary)
    )
    .from<Employee>()
    .left_join<Department>().on(
      sqlgen::column<Employee>(&Employee::department_id) == 
      sqlgen::column<Department>(&Department::department_id)
    );

  analysis.left_join_results = left_join_query.exec(db);

  // 3. RIGHT JOIN: All departments (even without employees)
  // Note: SQLite doesn't natively support RIGHT JOIN, so we simulate it with LEFT JOIN
  auto right_join_query = sqlgen::query<JoinResult>()
    .select(
      sqlgen::column<Department>(&Department::department_name).as(&JoinResult::department_name),
      sqlgen::column<Employee>(&Employee::first_name).as(&JoinResult::first_name),
      sqlgen::column<Employee>(&Employee::last_name).as(&JoinResult::last_name),
      sqlgen::column<Employee>(&Employee::salary).as(&JoinResult::salary)
    )
    .from<Department>()
    .left_join<Employee>().on(
      sqlgen::column<Department>(&Department::department_id) == 
      sqlgen::column<Employee>(&Employee::department_id)
    );

  analysis.right_join_results = right_join_query.exec(db);

  // 4. FULL JOIN: All employees and all departments
  // Note: SQLite doesn't natively support FULL JOIN, so we simulate it with UNION of LEFT and RIGHT joins
  auto full_join_query_left = sqlgen::query<JoinResult>()
    .select(
      sqlgen::column<Department>(&Department::department_name).as(&JoinResult::department_name),
      sqlgen::column<Employee>(&Employee::first_name).as(&JoinResult::first_name),
      sqlgen::column<Employee>(&Employee::last_name).as(&JoinResult::last_name),
      sqlgen::column<Employee>(&Employee::salary).as(&JoinResult::salary)
    )
    .from<Employee>()
    .left_join<Department>().on(
      sqlgen::column<Employee>(&Employee::department_id) == 
      sqlgen::column<Department>(&Department::department_id)
    );

  auto full_join_query_right = sqlgen::query<JoinResult>()
    .select(
      sqlgen::column<Department>(&Department::department_name).as(&JoinResult::department_name),
      sqlgen::column<Employee>(&Employee::first_name).as(&JoinResult::first_name),
      sqlgen::column<Employee>(&Employee::last_name).as(&JoinResult::last_name),
      sqlgen::column<Employee>(&Employee::salary).as(&JoinResult::salary)
    )
    .from<Department>()
    .left_join<Employee>().on(
      sqlgen::column<Department>(&Department::department_id) == 
      sqlgen::column<Employee>(&Employee::department_id)
    )
    .where(sqlgen::column<Employee>(&Employee::employee_id).is_null());

  // Execute both parts and combine for FULL JOIN simulation
  auto left_part = full_join_query_left.exec(db);
  auto right_part = full_join_query_right.exec(db);

  analysis.full_join_results = left_part;
  analysis.full_join_results.insert(analysis.full_join_results.end(), 
                                   right_part.begin(), right_part.end());

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to SQLite database** "test_db.sqlite" using `sqlgen::SQLiteDB`
2. **Creates tables** for Department and Employee using `sqlgen::Table`
3. **Inserts data** from the provided vectors into the respective tables
4. **Performs four types of joins** using `sqlgen::query`:
   - **INNER JOIN**: Gets only employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even those without departments)
   - **RIGHT JOIN**: Includes all departments (even those without employees) - simulated with LEFT JOIN since SQLite doesn't natively support RIGHT JOIN
   - **FULL JOIN**: Includes all records from both tables - simulated using UNION of LEFT JOIN and filtered RIGHT JOIN
5. **Returns comprehensive analysis** with results from all join operations in the `JoinAnalysis` structure

The code handles the optional nature of fields in join results using `std::optional` and properly maps the SQL columns to the C++ struct fields using the `sqlgen` library's type-safe query builder.

