  std::string full_name;
};

/**
 * This function demonstrates CONCAT usage.
 * Returns: query value.
 */
inline auto concat_function() {
    // Create a query that selects the concatenated full name
    auto query = sqlgen::select(
        sqlgen::function("CONCAT", Person::first_name, " ", Person::last_name).as("full_name")
    ).from<Person>();

    return query;
}

}  // namespace concat_function
```

