/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  sqlgen::SQLite db("test_db.sqlite");

  // Use raw SQL query with strftime to extract weekday (0=Sunday, 6=Saturday)
  std::string sql = R"(
    SELECT 
      CAST(strftime('%w', sale_time) AS INTEGER) as weekday,
      SUM(quantity) as total_quantity
    FROM Sales
    GROUP BY weekday
    ORDER BY weekday
  )";

  // Execute the query
  auto results = db.exec(sql);

  // Convert results to WeekdayStats vector
  std::vector<WeekdayStats> stats;
  for (const auto& row : results) {
    WeekdayStats stat;
    stat.weekday = row["weekday"].get<int>();
    stat.total_quantity = row["total_quantity"].get<int>();
    stats.push_back(stat);
  }

  return stats;
}

}  // namespace weekday_sales_analysis
```

