```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  // Create database connection
  sqlgen::sqlite::connection conn("test_db.sqlite");

  // SQL query to group posts by user and compute aggregations
  std::string sql = R"(
    SELECT 
        u.user_id,
        u.name,
        COUNT(p.post_id) as post_count,
        AVG(LENGTH(p.content)) as avg_length
    FROM User u
    LEFT JOIN Post p ON u.user_id = p.user_id
    GROUP BY u.user_id, u.name
    ORDER BY u.user_id
  )";

  // Execute the query and return results
  return sqlgen::query<Stats>(conn, sql);
}

}  // namespace group_by_with_aggregations
```

