#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    // Create a SELECT query that filters records where value > 100
    auto select_query = sqlgen::select(sqlgen::all_columns<Target>())
                        .from<Source>()
                        .where(sqlgen::greater_than(&Source::value, 100));

    // Create the CREATE TABLE AS SELECT statement
    auto query = sqlgen::create_table<Target>().as_select(select_query);

    return query;
}

}  // namespace create_table_as_select
```

